script.text:

function load$TaxPersonalDetail$(g) {g.add_commandEvent(on$TaxPersonalDetail$ExecuteCommand);}
function dispose$TaxPersonalDetail$(g) {try {g.remove_commandEvent(on$TaxPersonalDetail$ExecuteCommand);} catch (ex) {}}
function on$TaxPersonalDetail$ExecuteCommand(sender, e) {
  var action = e.type.Action, g = sender, f = g.get_element().parentForm;
  switch (action) {
    case 'AfterCloneRow':
      g.setItemFieldValue('stt_rec0', e.type.Value, '');
      break;
    case 'AfterInsertRow':
      if (g._rowCount == 1) {
        g._setItemValue(1, g._getColumnOrder('doi_tuong'), f.getItemValue('doi_tuong'));
        g._setItemValue(1, g._getColumnOrder('hop_dong_yn'), f.getItemValue('hop_dong_yn'));
        g._setItemValue(1, g._getColumnOrder('tinh_thue_yn'), f.getItemValue('tinh_thue_yn'));
        g._setItemValue(1, g._getColumnOrder('tinh_gt_yn'), f.getItemValue('tinh_gt_yn'));
        g._setItemValue(1, g._getColumnOrder('uy_quyen_yn'), f.getItemValue('uy_quyen_yn'));
      }
    default:
      break;
  }
}

function onChange$GridDetail$ValidAuthorization(o) {
  var g = o.grid, r = g._activeRow, l1 = g._getColumnOrder('doi_tuong'), l2 = g._getColumnOrder('hop_dong_yn'), l3 = g._getColumnOrder('v_uy_quyen'), l4 = g._getColumnOrder('uy_quyen_yn');
  var v = g._getItemValue(r, l1) == '1' && g._getItemValue(r, l2) == '1';
  g._setItemValue(r, l3, v);
  if (!v) g._setItemValue(r, l4, 0);
}
